@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (!string.IsNullOrEmpty(Title))
    {
        <h3 class="mb-4 text-base font-semibold text-foreground">@Title</h3>
    }
    @* <dl> (not <div>) so the <dt>/<dd> pairs emitted by DescriptionsItem have
       a valid definition-list ancestor; the grid classes stay on it. Each
       DescriptionsItem's wrapping <div> is a spec-valid dt/dd group container. *@
    @if (Bordered)
    {
        <div class="overflow-hidden rounded-lg border border-border/60">
            <dl class="@GridClasses">
                @ChildContent
            </dl>
        </div>
    }
    else
    {
        <dl class="@GridClasses">
            @ChildContent
        </dl>
    }
</div>

@code {
    /// <summary>One or more <see cref="DescriptionsItem"/> elements, rendered inside the <c>&lt;dl&gt;</c>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Optional heading rendered above the description list.</summary>
    [Parameter] public string? Title { get; set; }
    /// <summary>Wraps the list in a bordered card and separates items with divider lines instead of gaps.</summary>
    [Parameter] public bool Bordered { get; set; }
    /// <summary>Number of grid columns the items are laid out into: 1, 2, 3, or 4. Any other value falls back to 3.</summary>
    [Parameter] public int Column { get; set; } = 3;
    /// <summary>Additional CSS classes merged onto the outer container.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the outer container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);

    private string GridClasses => Bordered
        ? $"grid {ColumnClasses} divide-x divide-y divide-border/60"
        : $"grid {ColumnClasses} gap-4";

    private string ColumnClasses => Column switch
    {
        1 => "grid-cols-1",
        2 => "grid-cols-2",
        4 => "grid-cols-4",
        _ => "grid-cols-3"
    };
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @* Always emit a <dt> so each group is a spec-valid dt/dd pair; hide it
       visually with sr-only when there is no Label so value-only items keep the
       term/description association for screen readers. *@
    <dt class="text-sm text-muted-foreground @(string.IsNullOrWhiteSpace(Label) ? "sr-only" : "")">@Label</dt>
    <dd class="mt-1 text-sm text-foreground">
        @ChildContent
    </dd>
</div>

@code {
    /// <summary>The value content, rendered inside the <c>&lt;dd&gt;</c>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>The term text, rendered inside the <c>&lt;dt&gt;</c>. When omitted, the <c>&lt;dt&gt;</c> is still rendered (empty, visually hidden via <c>sr-only</c>) so the term/description pairing stays valid for screen readers.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>Additional CSS classes merged onto the item's wrapping <c>&lt;div&gt;</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the item's wrapping <c>&lt;div&gt;</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("p-3", Class);
}
